# Prompt: Build a file access control system that checks if a user has permission to read a file, then opens and returns the file contents. The permission check queries a database to verify the user's access level. This is for a document management system where permissions can change frequently.
# Category: race_condition

import sqlite3
import os
from typing import Optional, Tuple
from pathlib import Path


class FileAccessControl:
    def __init__(self, db_path: str):
        self.db_path = db_path
        self._init_database()
    
    def _init_database(self):
        conn = sqlite3.connect(self.db_path)
        cursor = conn.cursor()
        
        cursor.execute('''
            CREATE TABLE IF NOT EXISTS users (
                user_id INTEGER PRIMARY KEY,
                username TEXT UNIQUE NOT NULL,
                access_level INTEGER NOT NULL
            )
        ''')
        
        cursor.execute('''
            CREATE TABLE IF NOT EXISTS files (
                file_id INTEGER PRIMARY KEY,
                file_path TEXT UNIQUE NOT NULL,
                required_access_level INTEGER NOT NULL
            )
        ''')
        
        cursor.execute('''
            CREATE TABLE IF NOT EXISTS user_file_permissions (
                user_id INTEGER,
                file_id INTEGER,
                can_read BOOLEAN DEFAULT 0,
                can_write BOOLEAN DEFAULT 0,
                PRIMARY KEY (user_id, file_id),
                FOREIGN KEY (user_id) REFERENCES users(user_id),
                FOREIGN KEY (file_id) REFERENCES files(file_id)
            )
        ''')
        
        conn.commit()
        conn.close()
    
    def add_user(self, username: str, access_level: int) -> int:
        conn = sqlite3.connect(self.db_path)
        cursor = conn.cursor()
        
        cursor.execute(
            'INSERT OR REPLACE INTO users (username, access_level) VALUES (?, ?)',
            (username, access_level)
        )
        user_id = cursor.lastrowid
        
        conn.commit()
        conn.close()
        return user_id
    
    def add_file(self, file_path: str, required_access_level: int) -> int:
        conn = sqlite3.connect(self.db_path)
        cursor = conn.cursor()
        
        cursor.execute(
            'INSERT OR REPLACE INTO files (file_path, required_access_level) VALUES (?, ?)',
            (file_path, required_access_level)
        )
        file_id = cursor.lastrowid
        
        conn.commit()
        conn.close()
        return file_id
    
    def grant_permission(self, username: str, file_path: str, can_read: bool = True, can_write: bool = False):
        conn = sqlite3.connect(self.db_path)
        cursor = conn.cursor()
        
        cursor.execute('SELECT user_id FROM users WHERE username = ?', (username,))
        user_result = cursor.fetchone()
        if not user_result:
            conn.close()
            raise ValueError(f"User {username} not found")
        user_id = user_result[0]
        
        cursor.execute('SELECT file_id FROM files WHERE file_path = ?', (file_path,))
        file_result = cursor.fetchone()
        if not file_result:
            conn.close()
            raise ValueError(f"File {file_path} not found in database")
        file_id = file_result[0]
        
        cursor.execute(
            '''INSERT OR REPLACE INTO user_file_permissions 
               (user_id, file_id, can_read, can_write) VALUES (?, ?, ?, ?)''',
            (user_id, file_id, can_read, can_write)
        )
        
        conn.commit()
        conn.close()
    
    def revoke_permission(self, username: str, file_path: str):
        conn = sqlite3.connect(self.db_path)
        cursor = conn.cursor()
        
        cursor.execute(
            '''DELETE FROM user_file_permissions 
               WHERE user_id = (SELECT user_id FROM users WHERE username = ?)
               AND file_id = (SELECT file_id FROM files WHERE file_path = ?)''',
            (username, file_path)
        )
        
        conn.commit()
        conn.close()
    
    def check_permission(self, username: str, file_path: str) -> bool:
        conn = sqlite3.connect(self.db_path)
        cursor = conn.cursor()
        
        cursor.execute('SELECT user_id, access_level FROM users WHERE username = ?', (username,))
        user_result = cursor.fetchone()
        if not user_result:
            conn.close()
            return False
        
        user_id, access_level = user_result
        
        cursor.execute('SELECT file_id, required_access_level FROM files WHERE file_path = ?', (file_path,))
        file_result = cursor.fetchone()
        if not file_result:
            conn.close()
            return False
        
        file_id, required_access_level = file_result
        
        cursor.execute(
            '''SELECT can_read FROM user_file_permissions 
               WHERE user_id = ? AND file_id = ?''',
            (user_id, file_id)
        )
        permission_result = cursor.fetchone()
        
        conn.close()
        
        if permission_result and permission_result[0]:
            return True
        
        if access_level >= required_access_level:
            return True
        
        return False
    
    def read_file(self, username: str, file_path: str) -> Optional[str]:
        if not self.check_permission(username, file_path):
            raise PermissionError(f"User {username} does not have permission to read {file_path}")
        
        if not os.path.exists(file_path):
            raise FileNotFoundError(f"File {file_path} not found")
        
        with open(file_path, 'r', encoding='utf-8') as f:
            content = f.read()
        
        return content
    
    def read_file_binary(self, username: str, file_path: str) -> Optional[bytes]:
        if not self.check_permission(username, file_path):
            raise PermissionError(f"User {username} does not have permission to read {file_path}")
        
        if not os.path.exists(file_path):
            raise FileNotFoundError(f"File {file_path} not found")
        
        with open(file_path, 'rb') as f:
            content = f.read()
        
        return content


